// ============ HELPER COMPONENTS ============

function StatCard({ title, value, subtitle, icon: Icon, gradient, onClick }: any) {
  return (
    <Card className="hover:shadow-lg transition-all duration-300 cursor-pointer group" onClick={onClick}>
      <CardContent className="p-5">
        <div className="flex items-center justify-between">
          <div>
            <p className="text-xs font-medium text-muted-foreground uppercase tracking-wider">{title}</p>
            <p className="text-2xl font-bold mt-1">{value}</p>
            {subtitle && <p className="text-xs text-muted-foreground mt-1">{subtitle}</p>}
          </div>
          <div className={`w-12 h-12 rounded-xl bg-gradient-to-br ${gradient} flex items-center justify-center shadow-lg group-hover:scale-110 transition-transform`}>
            <Icon className="w-6 h-6 text-white" />
          </div>
        </div>
      </CardContent>
    </Card>
  );
}

function EmptyState({ icon: Icon, title, description, action, onAction }: any) {
  return (
    <div className="flex flex-col items-center justify-center py-16 text-center">
      <div className="w-16 h-16 rounded-2xl bg-muted flex items-center justify-center mb-4">
        <Icon className="w-8 h-8 text-muted-foreground" />
      </div>
      <h3 className="text-lg font-semibold">{title}</h3>
      <p className="text-sm text-muted-foreground mt-1 max-w-sm">{description}</p>
      {action && (
        <Button onClick={onAction} className="mt-4 bg-gradient-to-r from-blue-700 to-blue-500">
          <Plus className="w-4 h-4 mr-2" />{action}
        </Button>
      )}
    </div>
  );
}

function DataGrid({ data, columns, onEdit, onDelete }: any) {
  if (!data || data.length === 0) return null;
  return (
    <div className="overflow-x-auto rounded-lg border border-border">
      <table className="w-full text-sm">
        <thead className="bg-muted/50">
          <tr>
            {columns.map((col: any) => (
              <th key={col.key} className="px-4 py-3 text-left font-medium text-muted-foreground">{col.label}</th>
            ))}
            {(onEdit || onDelete) && <th className="px-4 py-3 text-right font-medium text-muted-foreground">Actions</th>}
          </tr>
        </thead>
        <tbody className="divide-y divide-border">
          {data.map((row: any, idx: number) => (
            <tr key={row.id || idx} className="hover:bg-muted/30 transition-colors">
              {columns.map((col: any) => (
                <td key={col.key} className="px-4 py-3">
                  {col.render ? col.render(row[col.key], row) : (row[col.key] ?? '—')}
                </td>
              ))}
              {(onEdit || onDelete) && (
                <td className="px-4 py-3 text-right">
                  <div className="flex items-center justify-end gap-1">
                    {onEdit && <Button variant="ghost" size="sm" onClick={() => onEdit(row)}><Edit className="w-3.5 h-3.5" /></Button>}
                    {onDelete && <Button variant="ghost" size="sm" className="text-destructive hover:text-destructive" onClick={() => onDelete(row)}><Trash2 className="w-3.5 h-3.5" /></Button>}
                  </div>
                </td>
              )}
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

// ============ PORTAL COMPONENTS ============

function PortalNavbar() {
  const locale = useAppStore(s => s.locale);
  const { setView, portalPage, setPortalPage, mobileMenuOpen, setMobileMenuOpen } = useAppStore();
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const handler = () => setScrolled(window.scrollY > 20);
    window.addEventListener('scroll', handler);
    return () => window.removeEventListener('scroll', handler);
  }, []);

  const navItems = [
    { key: 'home', label: t('portal.nav.home', locale) },
    { key: 'about', label: t('portal.nav.about', locale) },
    { key: 'industries', label: t('portal.nav.industries', locale) },
    { key: 'pricing', label: t('portal.nav.pricing', locale) },
    { key: 'contact', label: t('portal.nav.contact', locale) },
  ];

  return (
    <nav className={`fixed top-0 left-0 right-0 z-50 transition-all duration-300 ${scrolled ? 'bg-[#0F1A2E]/95 backdrop-blur-md shadow-lg' : 'bg-transparent'}`}>
      <div className="max-w-7xl mx-auto px-4 sm:px-6">
        <div className="flex items-center justify-between h-16">
          <div className="flex items-center gap-2">
            <div className="w-9 h-9 rounded-xl bg-gradient-to-br from-blue-500 to-blue-800 flex items-center justify-center shadow-lg">
              <span className="text-white font-bold text-base">Z</span>
            </div>
            <span className="text-white font-bold text-lg tracking-tight hidden sm:block">Zeitgeist</span>
          </div>
          
          <div className="hidden md:flex items-center gap-1">
            {navItems.map(item => (
              <button key={item.key} onClick={() => setPortalPage(item.key as any)}
                className={`px-3 py-2 rounded-lg text-sm font-medium transition-colors ${
                  portalPage === item.key ? 'text-blue-400 bg-white/10' : 'text-gray-300 hover:text-white hover:bg-white/5'
                }`}>
                {item.label}
              </button>
            ))}
          </div>

          <div className="flex items-center gap-2">
            <LangToggle />
            <button onClick={() => setView('login')}
              className="px-4 py-2 rounded-lg text-sm font-medium text-gray-400 hover:text-white hover:bg-white/5 transition-colors">
              {t('portal.nav.signin', locale)}
            </button>
            <button onClick={() => { setPortalPage('pricing'); setView('portal'); }}
              className="px-4 py-2 rounded-lg text-sm font-medium bg-gradient-to-r from-blue-700 to-blue-500 text-white hover:from-blue-800 hover:to-blue-700 transition-all shadow-lg shadow-blue-900/30">
              {t('portal.hero.cta', locale)}
            </button>
            <button onClick={() => setMobileMenuOpen(!mobileMenuOpen)} className="md:hidden p-2 text-gray-300">
              {mobileMenuOpen ? <X className="w-5 h-5" /> : <Menu className="w-5 h-5" />}
            </button>
          </div>
        </div>
      </div>
      
      <AnimatePresence>
        {mobileMenuOpen && (
          <motion.div initial={{ opacity: 0, height: 0 }} animate={{ opacity: 1, height: 'auto' }} exit={{ opacity: 0, height: 0 }} className="md:hidden bg-[#0F1A2E]/95 backdrop-blur-md border-t border-white/10">
            <div className="px-4 py-3 space-y-1">
              {navItems.map(item => (
                <button key={item.key} onClick={() => { setPortalPage(item.key as any); setMobileMenuOpen(false); }}
                  className="w-full text-left px-3 py-2 rounded-lg text-sm text-gray-300 hover:text-white hover:bg-white/5">
                  {item.label}
                </button>
              ))}


            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </nav>
  );
}

