// --- SVG Chart Helpers ---
function SparklineSVG({ data, color = '#1D4ED8', width = 80, height = 28 }: { data: number[]; color?: string; width?: number; height?: number }) {
  if (data.length < 2) return <div style={{ width, height }} />;
  const min = Math.min(...data); const max = Math.max(...data);
  const range = max - min || 1;
  const pts = data.map((v, i) => `${(i / (data.length - 1)) * width},${height - ((v - min) / range) * (height - 4) - 2}`);
  return (
    <svg width={width} height={height} className="overflow-visible">
      <defs><linearGradient id={`sg-${color.replace('#','')}`} x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stopColor={color} stopOpacity="0.3" /><stop offset="100%" stopColor={color} stopOpacity="0" /></linearGradient></defs>
      <polyline fill="none" stroke={color} strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" points={pts.join(' ')} />
      <polygon fill={`url(#sg-${color.replace('#','')})`} points={`0,${height} ${pts.join(' ')} ${width},${height}`} />
    </svg>
  );
}

function DonutChartSVG({ segments, size = 120, strokeWidth = 14 }: { segments: { name: string; value: number; color: string }[]; size?: number; strokeWidth?: number }) {
  const total = segments.reduce((s, seg) => s + seg.value, 0) || 1;
  const radius = (size - strokeWidth) / 2;
  const cx = size / 2; const cy = size / 2;
  const circumference = 2 * Math.PI * radius;
  const offsets = segments.reduce((acc: number[], seg) => {
    const prevOffset = acc.length > 0 ? acc[acc.length - 1] : 0;
    acc.push(prevOffset + seg.value / total);
    return acc;
  }, []);
  return (
    <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`}>
      {segments.map((seg, i) => {
        const pct = seg.value / total;
        const dashLen = pct * circumference;
        const dashOffset = -(i > 0 ? offsets[i - 1] : 0) * circumference;
        return <circle key={i} cx={cx} cy={cy} r={radius} fill="none" stroke={seg.color} strokeWidth={strokeWidth} strokeDasharray={`${dashLen} ${circumference - dashLen}`} strokeDashoffset={dashOffset} className="transition-all duration-500" style={{ transformOrigin: 'center', transform: 'rotate(-90deg)' }} />;
      })}
    </svg>
  );
}

function ThreatGaugeSVG({ score, size = 120 }: { score: number; size?: number }) {
  const radius = (size - 16) / 2;
  const cx = size / 2; const cy = size / 2;
  const circumference = Math.PI * radius;
  const pct = Math.min(Math.max(score, 0), 100) / 100;
  const color = score <= 30 ? '#22C55E' : score <= 60 ? '#F59E0B' : score <= 80 ? '#F97316' : '#EF4444';
  return (
    <svg width={size} height={size * 0.7} viewBox={`0 0 ${size} ${size * 0.7}`}>
      <path d={`M ${8} ${size * 0.65} A ${radius} ${radius} 0 0 1 ${size - 8} ${size * 0.65}`} fill="none" stroke="currentColor" strokeWidth="10" className="text-muted/30" strokeLinecap="round" />
      <path d={`M ${8} ${size * 0.65} A ${radius} ${radius} 0 0 1 ${size - 8} ${size * 0.65}`} fill="none" stroke={color} strokeWidth="10" strokeDasharray={`${pct * circumference} ${circumference}`} strokeLinecap="round" className="transition-all duration-700" />
      <text x={cx} y={size * 0.58} textAnchor="middle" className="fill-foreground text-2xl font-bold" style={{ fontSize: '22px' }}>{score}</text>
      <text x={cx} y={size * 0.68} textAnchor="middle" className="fill-muted-foreground" style={{ fontSize: '9px' }}>THREAT SCORE</text>
    </svg>
  );
}

const COUNTRY_FLAGS: Record<string, string> = { TT: '🇹🇹', JM: '🇯🇲', BB: '🇧🇧', GY: '🇬🇾', SR: '🇸🇷', GD: '🇬🇩', LC: '🇱🇨', VC: '🇻🇨', AG: '🇦🇬', DM: '🇩🇲', KN: '🇰🇳', BS: '🇧🇸', US: '🇺🇸', GB: '🇬🇧', CA: '🇨🇦', Unknown: '🌍' };

function CTRealTimeClock() {
  const locale = useAppStore(s => s.locale);
  const [now, setNow] = useState(new Date());
  useEffect(() => { const t = setInterval(() => setNow(new Date()), 1000); return () => clearInterval(t); }, []);
  return <span className="font-mono text-xs text-muted-foreground tabular-nums">{now.toLocaleTimeString('en-US', { hour12: true, hour: '2-digit', minute: '2-digit', second: '2-digit' })}</span>;
}

function CTSystemStatusBanner({ stats }: { stats: any }) {
  const locale = useAppStore(s => s.locale);
  const suspicious = stats?.tenants?.suspiciousAccounts?.length || 0;
  const pending = stats?.tenants?.pendingApproval?.length || 0;
  const level = suspicious > 3 || pending > 5 ? 'critical' : suspicious > 1 || pending > 2 ? 'warning' : 'normal';
  const cfg = { normal: { bg: 'bg-green-50 dark:bg-green-950/20', border: 'border-green-200 dark:border-green-800', dot: 'bg-green-500', text: 'text-green-700 dark:text-green-400', label: t('ct.systemStatus.operational', locale) }, warning: { bg: 'bg-amber-50 dark:bg-amber-950/20', border: 'border-amber-200 dark:border-amber-800', dot: 'bg-amber-500', text: 'text-amber-700 dark:text-amber-400', label: t('ct.systemStatus.attention', locale) }, critical: { bg: 'bg-red-50 dark:bg-red-950/20', border: 'border-red-200 dark:border-red-800', dot: 'bg-red-500', text: 'text-red-700 dark:text-red-400', label: t('ct.systemStatus.critical', locale) } }[level];
  return (
    <div className={`flex items-center gap-3 px-4 py-2.5 rounded-lg border ${cfg.bg} ${cfg.border}`}>
      <span className={`relative flex h-2.5 w-2.5`}><span className={`animate-ping absolute inline-flex h-full w-full rounded-full ${cfg.dot} opacity-75`} /><span className={`relative inline-flex rounded-full h-2.5 w-2.5 ${cfg.dot}`} /></span>
      <span className={`text-sm font-medium ${cfg.text}`}>{cfg.label}</span>
      <span className="ml-auto flex items-center gap-4">
        {suspicious > 0 && <span className="text-xs text-muted-foreground">{suspicious} suspicious</span>}
        {pending > 0 && <span className="text-xs text-muted-foreground">{pending} pending</span>}
        <CTRealTimeClock />
      </span>
    </div>
  );
}

