// --- Recipe Costing Page ---
const RECIPE_CATEGORIES = ['Panadería', 'Pasteles', 'Repostería', 'Galletas', 'Salado', 'Otro'];
const INGREDIENT_UNITS = ['kg', 'g', 'l', 'ml', 'pcs', 'oz', 'lb'];
const INGREDIENT_CATEGORIES = ['Harinas', 'Azúcares', 'Grasas', 'Lácteos', 'Huevos', 'Levaduras', 'Frutas', 'Frutos Secos', 'Chocolates', 'Especias', 'Líquidos', 'Otros'];

// ============ COST CALCULATOR TOOL ============

function CostCalculatorTool({ currency }: { currency: string }) {
  const locale = useAppStore(s => s.locale);
  const [calcIngredients, setCalcIngredients] = useState<any[]>([{ name: '', cost: 0, qty: 0 }]);
  const [servings, setServings] = useState(1);
  const [targetFoodCost, setTargetFoodCost] = useState(30);
  const [overhead, setOverhead] = useState(0);

  const totalIngCost = calcIngredients.reduce((s: number, i: any) => s + (i.cost || 0) * (i.qty || 0), 0);
  const costWithOverhead = totalIngCost * (1 + (overhead || 0) / 100);
  const costPerServing = Math.max(servings, 1);
  const costEach = costWithOverhead / costPerServing;
  const suggestedPrice = costEach / (1 - (targetFoodCost || 30) / 100);
  const actualFoodCost = suggestedPrice > 0 ? (costEach / suggestedPrice) * 100 : 0;
  const actualMargin = 100 - actualFoodCost;

  const updateIng = (idx: number, field: string, value: any) => {
    setCalcIngredients(prev => prev.map((ing, i) => i === idx ? { ...ing, [field]: value } : ing));
  };
  const addIng = () => setCalcIngredients(prev => [...prev, { name: '', cost: 0, qty: 0 }]);
  const removeIng = (idx: number) => setCalcIngredients(prev => prev.filter((_, i) => i !== idx));

  return (
    <Card>
      <CardHeader><CardTitle className="text-base">Calculadora de Costos</CardTitle></CardHeader>
      <CardContent className="space-y-4">
        <div className="space-y-2">
          <div className="flex items-center justify-between">
            <Label className="font-semibold">Ingredientes</Label>
            <Button variant="outline" size="sm" onClick={addIng}><Plus className="w-3 h-3 mr-1" />Agregar</Button>
          </div>
          {calcIngredients.map((ing, idx) => (
            <div key={idx} className="grid grid-cols-[1fr_100px_100px_32px] gap-2 items-end">
              <div><Label className="text-xs">{idx === 0 ? 'Nombre' : ''}</Label><Input value={ing.name} onChange={e => updateIng(idx, 'name', e.target.value)} placeholder="Ingrediente" className="h-9" /></div>
              <div><Label className="text-xs">{idx === 0 ? 'Costo/Unidad' : ''}</Label><Input type="number" step="0.01" value={ing.cost} onChange={e => updateIng(idx, 'cost', parseFloat(e.target.value) || 0)} className="h-9" /></div>
              <div><Label className="text-xs">{idx === 0 ? 'Cantidad' : ''}</Label><Input type="number" step="0.01" value={ing.qty} onChange={e => updateIng(idx, 'qty', parseFloat(e.target.value) || 0)} className="h-9" /></div>
              <Button variant="ghost" size="icon" className="w-8 h-8 text-red-400 hover:text-red-600" onClick={() => removeIng(idx)}><X className="w-4 h-4" /></Button>
            </div>
          ))}
        </div>

        <div className="grid grid-cols-2 gap-4">
          <div><Label>Porciones</Label><Input type="number" value={servings} onChange={e => setServings(parseInt(e.target.value) || 1)} className="h-9" /></div>
          <div><Label>Overhead %</Label><Input type="number" value={overhead} onChange={e => setOverhead(parseFloat(e.target.value) || 0)} className="h-9" placeholder="0" /></div>
        </div>

        <div className="space-y-2">
          <div className="flex items-center justify-between">
            <Label>Food Cost Objetivo: {targetFoodCost}%</Label>
          </div>
          <input type="range" min="15" max="60" step="1" value={targetFoodCost} onChange={e => setTargetFoodCost(parseInt(e.target.value))} className="w-full accent-primary" />
          <div className="flex justify-between text-xs text-muted-foreground"><span>15%</span><span>60%</span></div>
        </div>

        <div className="rounded-lg border bg-muted/30 p-4 space-y-2">
          <div className="flex justify-between text-sm"><span className="text-muted-foreground">Costo Ingredientes</span><span className="font-medium">{formatCurrency(totalIngCost, currency)}</span></div>
          <div className="flex justify-between text-sm"><span className="text-muted-foreground">Con Overhead ({overhead}%)</span><span className="font-medium">{formatCurrency(costWithOverhead, currency)}</span></div>
          <div className="flex justify-between text-sm"><span className="text-muted-foreground">Costo por Porcion</span><span className="font-semibold">{formatCurrency(costEach, currency)}</span></div>
          <Separator />
          <div className="flex justify-between text-sm"><span className="text-muted-foreground">Precio Sugerido ({targetFoodCost}% food cost)</span><span className="text-lg font-bold text-green-600">{formatCurrency(suggestedPrice, currency)}</span></div>
          <Separator />
          <div className="flex justify-between text-sm">
            <span className="text-muted-foreground">Margen con precio sugerido</span>
            <span className={`font-bold ${actualMargin > 60 ? 'text-green-600' : actualMargin > 40 ? 'text-amber-600' : 'text-red-600'}`}>{actualMargin.toFixed(1)}%</span>
          </div>
          <Progress value={Math.min(Math.max(actualMargin, 0), 100)} className={`h-2`} />
        </div>
      </CardContent>
    </Card>
  );
}

function TenantRecipeCostingPage() {
  const locale = useAppStore(s => s.locale);
  const { currentTenant, currency } = useAppStore() as any;
  const tid = currentTenant?.id;
  const [recipes, setRecipes] = useState<any[]>([]);
  const [ingredients, setIngredients] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [categoryFilter, setCategoryFilter] = useState('all');
  const [sortBy, setSortBy] = useState('newest');

  // Recipe form state
  const [showRecipeDialog, setShowRecipeDialog] = useState(false);
  const [editingRecipe, setEditingRecipe] = useState<any>(null);
  const [recipeForm, setRecipeForm] = useState<any>({ name: '', description: '', category: '', servings: 1, prepTime: 0, cookTime: 0, sellingPrice: 0, recipeIngredients: [] });
  const [saving, setSaving] = useState(false);

  // Ingredient form state
  const [showIngDialog, setShowIngDialog] = useState(false);
  const [editingIng, setEditingIng] = useState<any>(null);
  const [ingForm, setIngForm] = useState<any>({ name: '', category: '', unit: 'g', costPerUnit: 0, quantity: 0, minStock: 0, supplier: '' });
  const [savingIng, setSavingIng] = useState(false);

  // Add ingredient to recipe state
  const [addingIng, setAddingIng] = useState(false);
  const [selectedIngId, setSelectedIngId] = useState('');
  const [newIngQty, setNewIngQty] = useState(0);

  const loadData = useCallback(() => {
    if (!tid) return;
    Promise.all([
      authFetch(`/api/tenant/${tid}/recipes`).then(r => r.json()).catch(() => []),
      authFetch(`/api/tenant/${tid}/ingredients`).then(r => r.json()).catch(() => []),
    ]).then(([rec, ing]) => {
      setRecipes(Array.isArray(rec) ? rec : []);
      setIngredients(Array.isArray(ing) ? ing : []);
      setLoading(false);
    }).catch(() => setLoading(false));
  }, [tid]);

  useEffect(() => { loadData(); }, [loadData]);

  // Recipe helpers
  const parseIngredients = (recipe: any) => {
    try { return typeof recipe.ingredients === 'string' ? JSON.parse(recipe.ingredients) : (recipe.ingredients || []); } catch { return []; }
  };
  const calcTotalCost = (ings: any[]) => ings.reduce((s: number, i: any) => s + (i.quantity || 0) * (i.costPerUnit || 0), 0);
  const calcMargin = (sellingPrice: number, costPerServing: number) => sellingPrice > 0 ? ((sellingPrice - costPerServing) / sellingPrice) * 100 : 0;
  const marginColor = (m: number) => m > 50 ? 'text-green-600' : m >= 20 ? 'text-amber-600' : 'text-red-600';
  const marginBg = (m: number) => m > 50 ? 'bg-green-500/10 border-green-500/30' : m >= 20 ? 'bg-amber-500/10 border-amber-500/30' : 'bg-red-500/10 border-red-500/30';

  // Filtered & sorted recipes
  const filteredRecipes = recipes
    .filter((r: any) => r.name?.toLowerCase().includes(search.toLowerCase()))
    .filter((r: any) => categoryFilter === 'all' || r.category === categoryFilter)
    .sort((a: any, b: any) => {
      if (sortBy === 'name') return (a.name || '').localeCompare(b.name || '');
      if (sortBy === 'cost') return (a.costPerServing || 0) - (b.costPerServing || 0);
      if (sortBy === 'margin') return calcMargin(b.sellingPrice || 0, b.costPerServing || 0) - calcMargin(a.sellingPrice || 0, a.costPerServing || 0);
      return new Date(b.createdAt || 0).getTime() - new Date(a.createdAt || 0).getTime();
    });

  // Recipe CRUD
  const openCreateRecipe = () => {
    setEditingRecipe(null);
    setRecipeForm({ name: '', description: '', category: '', servings: 1, prepTime: 0, cookTime: 0, sellingPrice: 0, recipeIngredients: [] });
    setShowRecipeDialog(true);
  };
  const openEditRecipe = (recipe: any) => {
    setEditingRecipe(recipe);
    setRecipeForm({
      name: recipe.name || '', description: recipe.description || '', category: recipe.category || '',
      servings: recipe.servings || 1, prepTime: recipe.prepTime || 0, cookTime: recipe.cookTime || 0,
      sellingPrice: recipe.sellingPrice || 0, recipeIngredients: parseIngredients(recipe),
    });
    setShowRecipeDialog(true);
  };
  const saveRecipe = async () => {
    if (!recipeForm.name) { toast.error('El nombre es obligatorio'); return; }
    setSaving(true);
    const totalCost = calcTotalCost(recipeForm.recipeIngredients);
    const costPerServing = recipeForm.servings > 0 ? totalCost / recipeForm.servings : 0;
    const payload = {
      ...(editingRecipe?.id ? { id: editingRecipe.id } : {}),
      name: recipeForm.name, description: recipeForm.description, category: recipeForm.category,
      servings: recipeForm.servings, prepTime: recipeForm.prepTime, cookTime: recipeForm.cookTime,
      sellingPrice: recipeForm.sellingPrice, costPerServing,
      ingredients: JSON.stringify(recipeForm.recipeIngredients),
      instructions: JSON.stringify([]),
    };
    await authFetch(`/api/tenant/${tid}/recipes`, { method: editingRecipe?.id ? 'PUT' : 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(payload) });
    setShowRecipeDialog(false); setSaving(false); loadData();
    toast.success(editingRecipe?.id ? 'Receta actualizada' : 'Receta creada');
  };
  const deleteRecipe = async (recipe: any) => {
    await authFetch(`/api/tenant/${tid}/recipes`, { method: 'DELETE', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ id: recipe.id }) });
    loadData(); toast.success('Receta eliminada');
  };

  // Ingredient picker for recipe
  const addIngredientToRecipe = () => {
    const ing = ingredients.find((i: any) => i.id === selectedIngId);
    if (!ing) return;
    setRecipeForm((prev: any) => ({
      ...prev,
      recipeIngredients: [...prev.recipeIngredients, { ingredientId: ing.id, name: ing.name, quantity: newIngQty, unit: ing.unit, costPerUnit: ing.costPerUnit }],
    }));
    setSelectedIngId(''); setNewIngQty(0); setAddingIng(false);
  };
  const removeIngredientFromRecipe = (idx: number) => {
    setRecipeForm((prev: any) => ({ ...prev, recipeIngredients: prev.recipeIngredients.filter((_: any, i: number) => i !== idx) }));
  };

  // Standalone Ingredient CRUD
  const openCreateIng = () => {
    setEditingIng(null);
    setIngForm({ name: '', category: '', unit: 'g', costPerUnit: 0, quantity: 0, minStock: 0, supplier: '' });
    setShowIngDialog(true);
  };
  const openEditIng = (ing: any) => {
    setEditingIng(ing);
    setIngForm({ name: ing.name || '', category: ing.category || '', unit: ing.unit || 'g', costPerUnit: ing.costPerUnit || 0, quantity: ing.quantity || 0, minStock: ing.minStock || 0, supplier: ing.supplier || '' });
    setShowIngDialog(true);
  };
  const saveIng = async () => {
    if (!ingForm.name) { toast.error('El nombre es obligatorio'); return; }
    setSavingIng(true);
    await authFetch(`/api/tenant/${tid}/ingredients`, {
      method: editingIng?.id ? 'PUT' : 'POST', headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(editingIng?.id ? { id: editingIng.id, ...ingForm } : ingForm),
    });
    setShowIngDialog(false); setSavingIng(false); loadData();
    toast.success(editingIng?.id ? 'Ingrediente actualizado' : 'Ingrediente creado');
  };
  const deleteIng = async (ing: any) => {
    await authFetch(`/api/tenant/${tid}/ingredients`, { method: 'DELETE', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ id: ing.id }) });
    loadData(); toast.success('Ingrediente eliminado');
  };

  // Auto-calculated values for recipe form
  const formTotalCost = calcTotalCost(recipeForm.recipeIngredients);
  const formCostPerServing = recipeForm.servings > 0 ? formTotalCost / recipeForm.servings : 0;
  const formSuggestedPrice = formCostPerServing * 3;
  const formMargin = calcMargin(recipeForm.sellingPrice, formCostPerServing);

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div><h1 className="text-2xl font-bold">Costeo de Recetas</h1><p className="text-sm text-muted-foreground">Calcula costos y márgenes de tus recetas</p></div>
      </div>

      {/* Costing Dashboard Cards */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
        {(() => {
          const pricedRecipes = recipes.filter((r: any) => (r.sellingPrice || 0) > 0);
          const avgFoodCost = pricedRecipes.length > 0 ? pricedRecipes.reduce((s: number, r: any) => s + calcMargin(r.sellingPrice || 0, r.costPerServing || 0), 0) / pricedRecipes.length : 0;
          const avgMargin = 100 - avgFoodCost;
          const needsAdjust = recipes.filter((r: any) => { const m = calcMargin(r.sellingPrice || 0, r.costPerServing || 0); return (r.sellingPrice || 0) > 0 && m < 30; }).length;
          return [
            { label: 'Food Cost Prom.', value: `${avgFoodCost.toFixed(1)}%`, icon: PieChart, color: avgFoodCost < 35 ? 'text-green-600' : avgFoodCost < 45 ? 'text-amber-600' : 'text-red-600' },
            { label: 'Margen Prom.', value: `${avgMargin.toFixed(1)}%`, icon: TrendingUp, color: avgMargin > 50 ? 'text-green-600' : avgMargin > 30 ? 'text-amber-600' : 'text-red-600' },
            { label: t('recipe.stats.total', locale), value: recipes.length, icon: BookOpen, color: 'text-blue-600' },
            { label: 'Precios a Ajustar', value: needsAdjust, icon: AlertTriangle, color: needsAdjust > 0 ? 'text-red-600' : 'text-green-600' },
          ].map((s) => (
            <Card key={s.label}><CardContent className="p-4 flex items-center gap-3"><div className={`p-2 rounded-lg bg-muted/50 ${s.color}`}><s.icon className="w-5 h-5" /></div><div><p className="text-xs text-muted-foreground">{s.label}</p><p className="text-lg font-bold">{s.value}</p></div></CardContent></Card>
          ));
        })()}
      </div>

      <Tabs defaultValue="recipes">
        <TabsList>
          <TabsTrigger value="recipes"><ChefHat className="w-4 h-4 mr-2" />Recetas</TabsTrigger>
          <TabsTrigger value="margins"><TrendingUp className="w-4 h-4 mr-2" />Margenes</TabsTrigger>
          <TabsTrigger value="calculator"><Calculator className="w-4 h-4 mr-2" />Calculadora</TabsTrigger>
          <TabsTrigger value="ingredients"><Package className="w-4 h-4 mr-2" />Inventario</TabsTrigger>
        </TabsList>

        {/* ========== TAB 1: RECIPES ========== */}
        <TabsContent value="recipes" className="space-y-4">
          <div className="flex flex-col sm:flex-row gap-3">
            <div className="relative flex-1">
              <Search className="w-4 h-4 absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" />
              <Input placeholder="Buscar receta..." value={search} onChange={e => setSearch(e.target.value)} className="pl-10" />
            </div>
            <Select value={categoryFilter} onValueChange={setCategoryFilter}>
              <SelectTrigger className="w-full sm:w-44"><SelectValue placeholder="Categoría" /></SelectTrigger>
              <SelectContent>
                <SelectItem value="all">Todas</SelectItem>
                {RECIPE_CATEGORIES.map(c => <SelectItem key={c} value={c}>{c}</SelectItem>)}
              </SelectContent>
            </Select>
            <Select value={sortBy} onValueChange={setSortBy}>
              <SelectTrigger className="w-full sm:w-44"><SelectValue placeholder="Ordenar" /></SelectTrigger>
              <SelectContent>
                <SelectItem value="newest">Más reciente</SelectItem>
                <SelectItem value="name">Nombre</SelectItem>
                <SelectItem value="cost">Costo</SelectItem>
                <SelectItem value="margin">Margen</SelectItem>
              </SelectContent>
            </Select>
            <Button onClick={openCreateRecipe} className="bg-gradient-to-r from-blue-700 to-blue-500 whitespace-nowrap"><Plus className="w-4 h-4 mr-2" />Nueva Receta</Button>
          </div>

          {loading ? <PageSkeleton type="table" /> : filteredRecipes.length === 0 ? (
            <EmptyState icon={ChefHat} title="Sin recetas" description="Crea tu primera receta para calcular costos" action="Nueva Receta" onAction={openCreateRecipe} />
          ) : (
            <div className="grid sm:grid-cols-2 lg:grid-cols-3 gap-4">
              {filteredRecipes.map((recipe: any) => {
                const ings = parseIngredients(recipe);
                const margin = calcMargin(recipe.sellingPrice || 0, recipe.costPerServing || 0);
                return (
                  <motion.div key={recipe.id} initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.2 }}>
                    <Card className="h-full hover:shadow-md transition-shadow">
                      <CardHeader className="pb-3">
                        <div className="flex items-start justify-between">
                          <div className="flex-1 min-w-0">
                            <CardTitle className="text-base truncate">{recipe.name}</CardTitle>
                            {recipe.category && <Badge variant="secondary" className="mt-1">{recipe.category}</Badge>}
                          </div>
                          <div className="flex gap-1 ml-2">
                            <Button variant="ghost" size="icon" className="w-8 h-8" onClick={() => openEditRecipe(recipe)}><Edit className="w-4 h-4" /></Button>
                            <Button variant="ghost" size="icon" className="w-8 h-8 text-red-500 hover:text-red-700" onClick={() => deleteRecipe(recipe)}><Trash2 className="w-4 h-4" /></Button>
                          </div>
                        </div>
                      </CardHeader>
                      <CardContent className="space-y-3">
                        <div className="flex justify-between text-sm">
                          <span className="text-muted-foreground">Porciones</span>
                          <span className="font-medium">{recipe.servings || 1}</span>
                        </div>
                        <div className="flex justify-between text-sm">
                          <span className="text-muted-foreground">Costo/Porción</span>
                          <span className="font-medium">{formatCurrency(recipe.costPerServing || 0, currency)}</span>
                        </div>
                        <div className="flex justify-between text-sm">
                          <span className="text-muted-foreground">Precio Venta</span>
                          <span className="font-medium">{formatCurrency(recipe.sellingPrice || 0, currency)}</span>
                        </div>
                        <Separator />
                        <div className="flex items-center justify-between">
                          <span className="text-sm text-muted-foreground">Margen Bruto</span>
                          <Badge className={`${marginBg(margin)} border font-semibold`} variant="outline">
                            <TrendingUp className="w-3 h-3 mr-1" />{margin.toFixed(1)}%
                          </Badge>
                        </div>
                        <Progress value={Math.min(margin, 100)} className={`h-2 [&>div]:${margin > 50 ? 'bg-green-500' : margin >= 20 ? 'bg-amber-500' : 'bg-red-500'}`} />
                        {recipe.prepTime > 0 && <p className="text-xs text-muted-foreground">Prep: {recipe.prepTime}min · Cocción: {recipe.cookTime}min</p>}
                      </CardContent>
                    </Card>
                  </motion.div>
                );
              })}
            </div>
          )}
        </TabsContent>

        {/* ========== TAB 2: MARGIN ANALYSIS ========== */}
        <TabsContent value="margins" className="space-y-4">
          <div className="overflow-x-auto rounded-lg border border-border">
            <table className="w-full text-sm">
              <thead>
                <tr className="border-b bg-muted/50">
                  <th className="text-left p-3 font-medium">Receta</th>
                  <th className="text-left p-3 font-medium">Categoria</th>
                  <th className="text-right p-3 font-medium">Costo Total</th>
                  <th className="text-right p-3 font-medium">Costo/Porcion</th>
                  <th className="text-right p-3 font-medium">Precio Venta</th>
                  <th className="text-right p-3 font-medium">Food Cost %</th>
                  <th className="text-right p-3 font-medium">Margen %</th>
                  <th className="text-center p-3 font-medium">{t("pm.filter.status", locale)}</th>
                </tr>
              </thead>
              <tbody>
                {filteredRecipes.map((recipe: any) => {
                  const margin = calcMargin(recipe.sellingPrice || 0, recipe.costPerServing || 0);
                  const foodCostPct = 100 - margin;
                  const servings = Math.max(recipe.servings || 1, 1);
                  const ings = parseIngredients(recipe);
                  const totalCost = calcTotalCost(ings);
                  let statusLabel = 'Critico', statusColor = 'bg-red-500/10 text-red-600 border-red-500/30';
                  if (margin > 70) { statusLabel = 'Excelente'; statusColor = 'bg-green-500/10 text-green-600 border-green-500/30'; }
                  else if (margin > 50) { statusLabel = 'Bueno'; statusColor = 'bg-blue-500/10 text-blue-600 border-blue-500/30'; }
                  else if (margin > 30) { statusLabel = 'Bajo'; statusColor = 'bg-amber-500/10 text-amber-600 border-amber-500/30'; }
                  return (
                    <tr key={recipe.id} className="border-b hover:bg-muted/30">
                      <td className="p-3 font-medium">{recipe.name}</td>
                      <td className="p-3"><Badge variant="secondary">{recipe.category || '—'}</Badge></td>
                      <td className="p-3 text-right">{formatCurrency(totalCost, currency)}</td>
                      <td className="p-3 text-right">{formatCurrency(recipe.costPerServing || 0, currency)}</td>
                      <td className="p-3 text-right">{formatCurrency(recipe.sellingPrice || 0, currency)}</td>
                      <td className={`p-3 text-right font-medium ${foodCostPct < 30 ? 'text-green-600' : foodCostPct < 40 ? 'text-amber-600' : 'text-red-600'}`}>{(recipe.sellingPrice || 0) > 0 ? `${foodCostPct.toFixed(1)}%` : '—'}</td>
                      <td className={`p-3 text-right font-bold ${marginColor(margin)}`}>{(recipe.sellingPrice || 0) > 0 ? `${margin.toFixed(1)}%` : '—'}</td>
                      <td className="p-3 text-center">{(recipe.sellingPrice || 0) > 0 ? <Badge className={`${statusColor} border`} variant="outline">{statusLabel}</Badge> : <span className="text-xs text-muted-foreground">Sin precio</span>}</td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </TabsContent>

        {/* ========== TAB 3: COST CALCULATOR ========== */}
        <TabsContent value="calculator" className="space-y-4">
          <CostCalculatorTool currency={currency} />
        </TabsContent>

        {/* ========== TAB 4: INGREDIENTS INVENTORY ========== */}
        <TabsContent value="ingredients" className="space-y-4">
          <div className="flex items-center justify-between">
            <p className="text-sm text-muted-foreground">{ingredients.length} ingredientes registrados</p>
            <Button onClick={openCreateIng} className="bg-gradient-to-r from-blue-700 to-blue-500"><Plus className="w-4 h-4 mr-2" />Nuevo Ingrediente</Button>
          </div>

          {loading ? <PageSkeleton type="table" /> : ingredients.length === 0 ? (
            <EmptyState icon={Package} title="Sin ingredientes" description="Agrega ingredientes para calcular costos de recetas" action="Nuevo Ingrediente" onAction={openCreateIng} />
          ) : (
            <div className="overflow-x-auto rounded-lg border border-border">
              <table className="w-full text-sm">
                <thead>
                  <tr className="border-b bg-muted/50">
                    <th className="text-left p-3 font-medium">Nombre</th>
                    <th className="text-left p-3 font-medium">{t("common.category", locale)}</th>
                    <th className="text-left p-3 font-medium">{t("pm.table.unit", locale)}</th>
                    <th className="text-right p-3 font-medium">Costo/Unidad</th>
                    <th className="text-right p-3 font-medium">Stock</th>
                    <th className="text-right p-3 font-medium">Mín.</th>
                    <th className="text-center p-3 font-medium">{t("pm.filter.status", locale)}</th>
                    <th className="text-right p-3 font-medium">{t("common.actions", locale)}</th>
                  </tr>
                </thead>
                <tbody>
                  {ingredients.map((ing: any) => {
                    const isLow = (ing.quantity || 0) <= (ing.minStock || 0);
                    return (
                      <tr key={ing.id} className="border-b hover:bg-muted/30 transition-colors">
                        <td className="p-3 font-medium">{ing.name}</td>
                        <td className="p-3"><Badge variant="secondary">{ing.category || '—'}</Badge></td>
                        <td className="p-3">{ing.unit}</td>
                        <td className="p-3 text-right">{formatCurrency(ing.costPerUnit || 0, currency)}</td>
                        <td className={`p-3 text-right ${isLow ? 'text-red-600 font-semibold' : ''}`}>{ing.quantity || 0}</td>
                        <td className="p-3 text-right">{ing.minStock || 0}</td>
                        <td className="p-3 text-center">
                          {isLow ? <Badge className="bg-red-500/10 text-red-600 border border-red-500/30"><AlertTriangle className="w-3 h-3 mr-1" />Stock bajo</Badge> : <Badge className="bg-green-500/10 text-green-600 border border-green-500/30">OK</Badge>}
                        </td>
                        <td className="p-3 text-right">
                          <div className="flex justify-end gap-1">
                            <Button variant="ghost" size="icon" className="w-8 h-8" onClick={() => openEditIng(ing)}><Edit className="w-4 h-4" /></Button>
                            <Button variant="ghost" size="icon" className="w-8 h-8 text-red-500 hover:text-red-700" onClick={() => deleteIng(ing)}><Trash2 className="w-4 h-4" /></Button>
                          </div>
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          )}
        </TabsContent>
      </Tabs>

      {/* ========== RECIPE CREATE/EDIT DIALOG ========== */}
      <Dialog open={showRecipeDialog} onOpenChange={setShowRecipeDialog}>
        <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle>{editingRecipe ? 'Editar Receta' : 'Nueva Receta'}</DialogTitle>
          </DialogHeader>
          <div className="space-y-4 mt-4">
            <div className="grid sm:grid-cols-2 gap-4">
              <div><Label>Nombre *</Label><Input value={recipeForm.name} onChange={e => setRecipeForm(p => ({ ...p, name: e.target.value }))} placeholder="Ej: Pan de Mantequilla" /></div>
              <div><Label>{t("common.category", locale)}</Label><Select value={recipeForm.category} onValueChange={v => setRecipeForm(p => ({ ...p, category: v }))}><SelectTrigger><SelectValue placeholder={t("common.all", locale)} /></SelectTrigger><SelectContent>{RECIPE_CATEGORIES.map(c => <SelectItem key={c} value={c}>{c}</SelectItem>)}</SelectContent></Select></div>
            </div>
            <div><Label>{t("common.description", locale)}</Label><Textarea value={recipeForm.description} onChange={e => setRecipeForm(p => ({ ...p, description: e.target.value }))} rows={2} placeholder={t("common.description", locale)} /></div>
            <div className="grid grid-cols-3 gap-4">
              <div><Label>Porciones</Label><Input type="number" value={recipeForm.servings} onChange={e => setRecipeForm(p => ({ ...p, servings: parseInt(e.target.value) || 1 }))} /></div>
              <div><Label>Tiempo Prep (min)</Label><Input type="number" value={recipeForm.prepTime} onChange={e => setRecipeForm(p => ({ ...p, prepTime: parseInt(e.target.value) || 0 }))} /></div>
              <div><Label>Tiempo Cocción (min)</Label><Input type="number" value={recipeForm.cookTime} onChange={e => setRecipeForm(p => ({ ...p, cookTime: parseInt(e.target.value) || 0 }))} /></div>
            </div>
            <div><Label>Precio de Venta</Label><Input type="number" step="0.01" value={recipeForm.sellingPrice} onChange={e => setRecipeForm(p => ({ ...p, sellingPrice: parseFloat(e.target.value) || 0 }))} placeholder="0.00" /></div>

            <Separator />
            <div className="space-y-3">
              <div className="flex items-center justify-between">
                <Label className="text-base font-semibold">Ingredientes</Label>
                <Button variant="outline" size="sm" onClick={() => setAddingIng(!addingIng)}><Plus className="w-4 h-4 mr-1" />Agregar</Button>
              </div>

              {addingIng && (
                <motion.div initial={{ opacity: 0, height: 0 }} animate={{ opacity: 1, height: 'auto' }} className="flex flex-col sm:flex-row gap-2 p-3 rounded-lg border bg-muted/30">
                  <Select value={selectedIngId} onValueChange={setSelectedIngId}>
                    <SelectTrigger className="flex-1"><SelectValue placeholder="Seleccionar ingrediente..." /></SelectTrigger>
                    <SelectContent>
                      {ingredients.filter(i => !recipeForm.recipeIngredients.some((ri: any) => ri.ingredientId === i.id)).map(i => (
                        <SelectItem key={i.id} value={i.id}>{i.name} ({formatCurrency(i.costPerUnit || 0, currency)}/{i.unit})</SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                  <Input type="number" step="0.01" placeholder="Cantidad" value={newIngQty} onChange={e => setNewIngQty(parseFloat(e.target.value) || 0)} className="w-32" />
                  <Button onClick={addIngredientToRecipe} disabled={!selectedIngId || newIngQty <= 0} size="sm"><Check className="w-4 h-4" /></Button>
                  <Button variant="ghost" size="sm" onClick={() => { setAddingIng(false); setSelectedIngId(''); setNewIngQty(0); }}><X className="w-4 h-4" /></Button>
                </motion.div>
              )}

              {recipeForm.recipeIngredients.length === 0 ? (
                <p className="text-sm text-muted-foreground text-center py-4">Sin ingredientes agregados</p>
              ) : (
                <div className="space-y-2 max-h-48 overflow-y-auto">
                  {recipeForm.recipeIngredients.map((ri: any, idx: number) => (
                    <div key={idx} className="flex items-center justify-between gap-2 p-2 rounded-md border bg-background">
                      <div className="flex-1 min-w-0">
                        <p className="text-sm font-medium truncate">{ri.name}</p>
                        <p className="text-xs text-muted-foreground">{ri.quantity} {ri.unit} × {formatCurrency(ri.costPerUnit, currency)}</p>
                      </div>
                      <span className="text-sm font-semibold whitespace-nowrap">{formatCurrency(ri.quantity * ri.costPerUnit, currency)}</span>
                      <Button variant="ghost" size="icon" className="w-7 h-7 text-red-500 hover:text-red-700 shrink-0" onClick={() => removeIngredientFromRecipe(idx)}><X className="w-3 h-3" /></Button>
                    </div>
                  ))}
                </div>
              )}
            </div>

            {/* Auto-calculated summary */}
            <div className="rounded-lg border bg-muted/30 p-4 space-y-2">
              <div className="flex justify-between text-sm"><span className="text-muted-foreground">Costo Total Ingredientes</span><span className="font-semibold">{formatCurrency(formTotalCost, currency)}</span></div>
              <div className="flex justify-between text-sm"><span className="text-muted-foreground">Costo por Porción</span><span className="font-semibold">{formatCurrency(formCostPerServing, currency)}</span></div>
              <div className="flex justify-between text-sm"><span className="text-muted-foreground">Precio Sugerido (3×)</span><span className="font-semibold text-green-600">{formatCurrency(formSuggestedPrice, currency)}</span></div>
              <Separator />
              <div className="flex justify-between text-sm">
                <span className="text-muted-foreground">Margen Bruto</span>
                <span className={`font-bold ${marginColor(formMargin)}`}>{recipeForm.sellingPrice > 0 ? `${formMargin.toFixed(1)}%` : '—'}</span>
              </div>
              {recipeForm.sellingPrice > 0 && <Progress value={Math.min(Math.max(formMargin, 0), 100)} className="h-2" />}
            </div>

            <Button onClick={saveRecipe} disabled={saving || !recipeForm.name} className="w-full bg-gradient-to-r from-blue-700 to-blue-500">
              {saving && <Loader2 className="w-4 h-4 mr-2 animate-spin" />}{editingRecipe ? 'Guardar Cambios' : 'Crear Receta'}
            </Button>
          </div>
        </DialogContent>
      </Dialog>

      {/* ========== INGREDIENT CREATE/EDIT DIALOG ========== */}
      <Dialog open={showIngDialog} onOpenChange={setShowIngDialog}>
        <DialogContent className="max-w-lg">
          <DialogHeader>
            <DialogTitle>{editingIng ? 'Editar Ingrediente' : 'Nuevo Ingrediente'}</DialogTitle>
          </DialogHeader>
          <div className="space-y-4 mt-4">
            <div><Label>Nombre *</Label><Input value={ingForm.name} onChange={e => setIngForm(p => ({ ...p, name: e.target.value }))} placeholder="Ej: Harina de trigo" /></div>
            <div><Label>{t("common.category", locale)}</Label><Select value={ingForm.category} onValueChange={v => setIngForm(p => ({ ...p, category: v }))}><SelectTrigger><SelectValue placeholder={t("common.all", locale)} /></SelectTrigger><SelectContent>{INGREDIENT_CATEGORIES.map(c => <SelectItem key={c} value={c}>{c}</SelectItem>)}</SelectContent></Select></div>
            <div className="grid grid-cols-2 gap-4">
              <div><Label>{t("pm.table.unit", locale)}</Label><Select value={ingForm.unit} onValueChange={v => setIngForm(p => ({ ...p, unit: v }))}><SelectTrigger><SelectValue /></SelectTrigger><SelectContent>{INGREDIENT_UNITS.map(u => <SelectItem key={u} value={u}>{u}</SelectItem>)}</SelectContent></Select></div>
              <div><Label>Costo por Unidad</Label><Input type="number" step="0.01" value={ingForm.costPerUnit} onChange={e => setIngForm(p => ({ ...p, costPerUnit: parseFloat(e.target.value) || 0 }))} /></div>
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div><Label>Stock Actual</Label><Input type="number" value={ingForm.quantity} onChange={e => setIngForm(p => ({ ...p, quantity: parseFloat(e.target.value) || 0 }))} /></div>
              <div><Label>Stock Mínimo</Label><Input type="number" value={ingForm.minStock} onChange={e => setIngForm(p => ({ ...p, minStock: parseFloat(e.target.value) || 0 }))} /></div>
            </div>
            <div><Label>{t("pm.table.vendor", locale)}</Label><Input value={ingForm.supplier} onChange={e => setIngForm(p => ({ ...p, supplier: e.target.value }))} placeholder="Nombre del proveedor" /></div>
            <Button onClick={saveIng} disabled={savingIng || !ingForm.name} className="w-full bg-gradient-to-r from-blue-700 to-blue-500">
              {savingIng && <Loader2 className="w-4 h-4 mr-2 animate-spin" />}{editingIng ? 'Guardar Cambios' : 'Crear Ingrediente'}
            </Button>
          </div>
        </DialogContent>
      </Dialog>
    </div>
  );
}

function TenantPOSPage() {
  const { currentTenant, currency, locale } = useAppStore() as any;
  const [products, setProducts] = useState<any[]>([]);
  const [cart, setCart] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [categoryFilter, setCategoryFilter] = useState('all');
  const [customerName, setCustomerName] = useState('');
  const [paymentMethod, setPaymentMethod] = useState<'cash' | 'card' | 'transfer' | 'gift_card'>('cash');
  const [discountPct, setDiscountPct] = useState(0);
  const [cashReceived, setCashReceived] = useState(0);
  const [receiptOrder, setReceiptOrder] = useState<any>(null);
  const [todaySales, setTodaySales] = useState<any[]>([]);
  const [heldSales, setHeldSales] = useState<any[]>([]);
  const [showHeldSales, setShowHeldSales] = useState(false);
  const [showScanner, setShowScanner] = useState(false);
  const [checkingOut, setCheckingOut] = useState(false);
  // Gift card state
  const [gcNumber, setGcNumber] = useState('');
  const [gcPin, setGcPin] = useState('');
  const [gcCard, setGcCard] = useState<any>(null);
  const [gcLoading, setGcLoading] = useState(false);
  // Split payment state
  const [isSplitPayment, setIsSplitPayment] = useState(false);
  const [splitSecondaryMethod, setSplitSecondaryMethod] = useState<'cash' | 'card' | 'transfer'>('cash');
  const tid = currentTenant?.id;

  const categories = ['all', ...Array.from(new Set((products || []).map((p: any) => p.category).filter(Boolean)))];

  useEffect(() => {
    if (tid) {
      authFetch(`/api/tenant/${tid}/retail-products`).then(r => r.json()).then(d => { setProducts(Array.isArray(d) ? d : []); setLoading(false); }).catch(() => setLoading(false));
      const today = new Date().toISOString().split('T')[0];
      authFetch(`/api/tenant/${tid}/pos-sales?from=${today}`).then(r => r.json()).then(d => { setTodaySales(Array.isArray(d) ? d : []); }).catch(() => {});
      try { const held = JSON.parse(localStorage.getItem(`zbs-held-sales-${tid}`) || '[]'); setHeldSales(held); } catch {}
    }
  }, [tid]);

  const saveHeldSales = (sales: any[]) => { setHeldSales(sales); try { localStorage.setItem(`zbs-held-sales-${tid}`, JSON.stringify(sales)); } catch {} };

  const filtered = (products || []).filter((p: any) => {
    const s = search.toLowerCase();
    const matchSearch = !s || p.name?.toLowerCase().includes(s) || p.sku?.toLowerCase().includes(s) || p.barcode?.toLowerCase().includes(s);
    const matchCat = categoryFilter === 'all' || !p.category || p.category.toLowerCase() === categoryFilter.toLowerCase();
    return matchSearch && matchCat;
  });

  const subtotal = cart.reduce((s: number, i: any) => s + i.price * i.qty, 0);
  const discountAmt = subtotal * (discountPct / 100);
  const afterDiscount = subtotal - discountAmt;
  const taxAmt = afterDiscount * (currentTenant?.taxRate || 0.125);
  const grandTotal = afterDiscount + taxAmt;
  const change = paymentMethod === 'cash' ? Math.max(0, cashReceived - grandTotal) : 0;

  const todaySalesCount = todaySales.length;
  const todaySalesTotal = todaySales.reduce((s: number, sale: any) => s + (sale.totalAmount || 0), 0);

  const addToCart = (p: any) => {
    const existing = cart.find((c: any) => c.id === p.id);
    const currentCartQty = existing ? existing.qty : 0;
    const available = (p.quantity || 0) - currentCartQty;
    if (available <= 0) {
      toast.error(t('pos.outOfStock', locale));
      return;
    }
    setCart(prev => { const ex = prev.find(i => i.id === p.id); return ex ? prev.map(i => i.id === p.id ? { ...i, qty: i.qty + 1 } : i) : [...prev, { ...p, qty: 1 }]; });
  };
  const updateQty = (id: string, qty: number) => {
    if (qty <= 0) { setCart(prev => prev.filter(i => i.id !== id)); return; }
    const product = products.find((p: any) => p.id === id);
    if (product && qty > (product.quantity || 0)) {
      toast.error(t('pos.outOfStock', locale));
      return;
    }
    setCart(prev => prev.map(i => i.id === id ? { ...i, qty } : i));
  };

  const handleBarcodeScanned = (product: any) => {
    if (product && product.id) {
      addToCart({ ...product, quantity: product.stock });
      toast.success(`${product.name} added to cart`);
    }
    setShowScanner(false);
  };

  const handleHoldSale = () => {
    if (cart.length === 0) return;
    const held = { id: Date.now().toString(), cart: [...cart], customerName, discountPct, paymentMethod, heldAt: new Date().toISOString() };
    const updated = [...heldSales, held];
    saveHeldSales(updated);
    setCart([]); setDiscountPct(0); setCashReceived(0); setCustomerName('');
    toast.success(t('pos.saleHeld', locale));
  };

  const handleResumeSale = (held: any) => {
    setCart(held.cart || []);
    setCustomerName(held.customerName || '');
    setDiscountPct(held.discountPct || 0);
    setPaymentMethod(held.paymentMethod || 'cash');
    saveHeldSales(heldSales.filter(h => h.id !== held.id));
  };

  const handleDeleteHeld = (heldId: string) => {
    saveHeldSales(heldSales.filter(h => h.id !== heldId));
  };

  const handleLookUpGiftCard = async () => {
    if (!gcNumber.trim()) return;
    setGcLoading(true);
    setGcCard(null);
    try {
      const url = `/api/tenant/${tid}/gift-cards?cardNumber=${encodeURIComponent(gcNumber.trim())}${gcPin.trim() ? '&cardCode=' + encodeURIComponent(gcPin.trim()) : ''}`;
      const res = await authFetchJSON(url);
      if (Array.isArray(res) && res.length > 0) {
        const card = res[0];
        // If PIN was provided, verify it matches
        if (gcPin.trim() && card.cardCode !== gcPin.trim()) {
          toast.error(t('pos.cardNotFound', locale));
        } else {
          setGcCard(card);
          // If card balance < grand total, auto-switch to split
          if (card.currentBalance < grandTotal && grandTotal > 0) {
            setIsSplitPayment(true);
          } else {
            setIsSplitPayment(false);
          }
        }
      } else {
        toast.error(t('pos.cardNotFound', locale));
      }
    } catch (e: any) { toast.error(e.message || t('pos.cardNotFound', locale)); }
    setGcLoading(false);
  };

  const handleCheckout = async () => {
    if (cart.length === 0) return;
    if (paymentMethod === 'cash' && !isSplitPayment && cashReceived < grandTotal) { toast.error(t('pos.insufficientCash', locale)); return; }
    if (paymentMethod === 'gift_card' && !gcCard) { toast.error(t('pos.cardNotFound', locale)); return; }
    if (paymentMethod === 'gift_card' && gcCard && gcCard.currentBalance < grandTotal && !isSplitPayment) { toast.error(t('pos.insufficientBalance', locale)); return; }
    if (isSplitPayment && paymentMethod === 'cash' && cashReceived < (gcCard ? grandTotal - gcCard.currentBalance : grandTotal)) { toast.error(t('pos.insufficientCash', locale)); return; }
    setCheckingOut(true);
    try {
      let effectivePaymentMethod: string = paymentMethod;
      let giftCardId: string | null = null;
      let splitDetails: any = null;
      let effectiveCashReceived = paymentMethod === 'cash' ? cashReceived : 0;
      let effectiveChange = change;

      if (paymentMethod === 'gift_card' && gcCard) {
        if (isSplitPayment && gcCard.currentBalance < grandTotal) {
          // Split: gift card covers what it can, secondary method covers rest
          effectivePaymentMethod = 'split';
          const gcAmount = gcCard.currentBalance;
          const remaining = Math.round((grandTotal - gcAmount) * 100) / 100;
          giftCardId = gcCard.id;
          splitDetails = {
            cash: splitSecondaryMethod === 'cash' ? remaining : 0,
            card: splitSecondaryMethod === 'card' ? remaining : 0,
            giftCard: gcAmount,
            transfer: splitSecondaryMethod === 'transfer' ? remaining : 0,
            giftCardId: gcCard.id,
          };
          if (splitSecondaryMethod === 'cash') {
            effectiveCashReceived = cashReceived;
            effectiveChange = Math.max(0, cashReceived - remaining);
          }
        } else {
          // Full gift card payment
          giftCardId = gcCard.id;
        }
      }

      const orderBody: any = {
        items: cart.map(i => ({ productId: i.id, name: i.name, sku: i.sku, qty: i.qty, price: i.price, cost: i.cost || 0 })),
        subtotal, discountPct, discountAmount: discountAmt, taxAmount: taxAmt, totalAmount: grandTotal,
        paymentMethod: effectivePaymentMethod, cashReceived: effectiveCashReceived, changeAmount: effectiveChange,
        currency, customerName: customerName || t('pos.walkIn', locale), status: 'completed',
      };
      if (giftCardId) orderBody.giftCardId = giftCardId;
      if (splitDetails) orderBody.splitDetails = splitDetails;

      const result = await authFetchJSON(`/api/tenant/${tid}/pos-sales`, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(orderBody) });
      const receiptOrder = { ...orderBody, id: result.saleNumber || `POS-${Date.now().toString(36).toUpperCase()}`, date: new Date().toISOString() };
      setReceiptOrder(receiptOrder);
      setCart([]); setDiscountPct(0); setCashReceived(0); setCustomerName('');
      setGcCard(null); setGcNumber(''); setGcPin(''); setIsSplitPayment(false);
      const today = new Date().toISOString().split('T')[0];
      authFetch(`/api/tenant/${tid}/pos-sales?from=${today}`).then(r => r.json()).then(d => { setTodaySales(Array.isArray(d) ? d : []); }).catch(() => {});
      toast.success(t('pos.saleComplete', locale));
    } catch (e: any) { toast.error(e.message); }
    setCheckingOut(false);
  };

  const handlePrint = () => { window.print(); };

  const paymentMethodLabel = (m: string) => m === 'cash' ? t('pos.cash', locale) : m === 'card' ? t('pos.card', locale) : m === 'transfer' ? t('pos.transfer', locale) : m === 'gift_card' ? t('pos.giftCard', locale) : t('pos.splitPayment', locale);

  const giftCardAmount = gcCard ? Math.min(gcCard.currentBalance, grandTotal) : 0;
  const remainingAmount = isSplitPayment && gcCard ? Math.max(0, Math.round((grandTotal - gcCard.currentBalance) * 100) / 100) : 0;

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between flex-wrap gap-4">
        <div><h1 className="text-2xl font-bold">{t('pos.title', locale)}</h1><p className="text-sm text-muted-foreground">{t('pos.subtitle', locale)}</p></div>
        <div className="flex items-center gap-2">
          {heldSales.length > 0 && (
            <Button variant="outline" size="sm" onClick={() => setShowHeldSales(true)}>
              {t('pos.heldSales', locale)} <Badge className="ml-1 bg-amber-500 text-white">{heldSales.length}</Badge>
            </Button>
          )}
          <Button variant="outline" size="sm" onClick={() => setShowScanner(true)}><ScanLine className="w-4 h-4 mr-2" />{t('pos.search', locale)}</Button>
        </div>
      </div>

      {/* Today's Sales Summary */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        <Card className="p-4"><div className="flex items-center justify-between"><div><p className="text-xs text-muted-foreground">{t('pos.today', locale)}</p><p className="text-2xl font-bold">{todaySalesCount}</p></div><ShoppingCart className="w-5 h-5 text-blue-500 opacity-60" /></div></Card>
        <Card className="p-4"><div className="flex items-center justify-between"><div><p className="text-xs text-muted-foreground">{t('pos.total', locale)}</p><p className="text-2xl font-bold">{formatCurrency(todaySalesTotal, currency)}</p></div><DollarSign className="w-5 h-5 text-green-500 opacity-60" /></div></Card>
      </div>

      <div className="grid lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2 space-y-4">
          <div className="flex gap-2">
            <div className="relative flex-1"><Search className="w-4 h-4 absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" /><Input placeholder={t('pos.search', locale)} value={search} onChange={e => setSearch(e.target.value)} className="pl-10" /></div>
            <Button variant="outline" size="icon" onClick={() => setShowScanner(true)}><ScanLine className="w-4 h-4" /></Button>
          </div>
          <div className="flex gap-2 flex-wrap">
            {categories.map(cat => (
              <Button key={cat} variant={categoryFilter === cat ? 'default' : 'outline'} size="sm" onClick={() => setCategoryFilter(cat)} className="text-xs">{cat === 'all' ? t('pos.all', locale) : cat}</Button>
            ))}
          </div>
          {loading ? <PageSkeleton type="table" /> : filtered.length === 0 ? <p className="text-center text-muted-foreground py-8">{t('pos.noProducts', locale)}</p> : (
            <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 gap-3 max-h-[55vh] overflow-y-auto">
              {filtered.map((p: any) => (
                <motion.button key={p.id} whileHover={{ scale: 1.02 }} whileTap={{ scale: 0.98 }} onClick={() => addToCart(p)} disabled={(p.quantity || 0) <= 0} className={`p-3 rounded-xl border text-left hover:border-primary/50 hover:bg-primary/5 transition-all relative ${(p.quantity || 0) <= 0 ? 'opacity-50 cursor-not-allowed' : ''}`}>
                  {(p.quantity || 0) <= 0 && <Badge className="absolute top-1 right-1 text-[10px] bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-400">{t('pos.voided', locale)}</Badge>}
                  <p className="font-medium text-sm truncate">{p.name}</p>
                  <p className="text-xs text-muted-foreground font-mono">{p.sku}</p>
                  <p className="font-bold text-primary mt-1">{formatCurrency(p.price, currency)}</p>
                  <p className="text-xs text-muted-foreground">{t('pos.stock', locale)}: {p.quantity || 0}</p>
                </motion.button>
              ))}
            </div>
          )}
        </div>

        {/* Cart */}
        <Card className="h-fit sticky top-4">
          <CardHeader className="pb-3"><CardTitle className="text-sm">{t('pos.cart', locale)} ({cart.length})</CardTitle></CardHeader>
          <CardContent className="space-y-3">
            <div><Label className="text-xs">{t('pos.customer', locale)}</Label><Input value={customerName} onChange={e => setCustomerName(e.target.value)} placeholder={t('pos.customerPlaceholder', locale)} className="mt-1" /></div>
            {cart.length === 0 ? <p className="text-sm text-muted-foreground text-center py-4">{t('pos.cartEmpty', locale)}</p> : (
              <div className="space-y-2 max-h-48 overflow-y-auto">
                {cart.map((item: any) => (
                  <div key={item.id} className="flex items-center justify-between gap-2">
                    <div className="flex-1 min-w-0"><p className="text-sm font-medium truncate">{item.name}</p><p className="text-xs text-muted-foreground">{formatCurrency(item.price, currency)} × {item.qty}</p></div>
                    <div className="flex items-center gap-1">
                      <Button variant="outline" size="icon" className="w-6 h-6" onClick={() => updateQty(item.id, item.qty - 1)}><Minus className="w-3 h-3" /></Button>
                      <span className="text-sm w-6 text-center">{item.qty}</span>
                      <Button variant="outline" size="icon" className="w-6 h-6" onClick={() => updateQty(item.id, item.qty + 1)}><Plus className="w-3 h-3" /></Button>
                    </div>
                  </div>
                ))}
              </div>
            )}
            <Separator />
            <div className="space-y-1 text-sm">
              <div className="flex justify-between"><span>{t('pos.subtotal', locale)}</span><span>{formatCurrency(subtotal, currency)}</span></div>
              <div className="flex items-center justify-between gap-2">
                <span>{t('pos.discount', locale)} (%)</span>
                <Input type="number" min={0} max={100} value={discountPct || ''} onChange={e => setDiscountPct(Math.min(100, Math.max(0, parseInt(e.target.value) || 0)))} className="w-16 h-7 text-xs text-right" />
              </div>
              {discountPct > 0 && <div className="flex justify-between text-amber-600"><span>{t('pos.discountLabel', locale)} -{discountPct}%</span><span>-{formatCurrency(discountAmt, currency)}</span></div>}
              <div className="flex justify-between"><span>{t('pos.tax', locale)}</span><span>{formatCurrency(taxAmt, currency)}</span></div>
              <Separator />
              <div className="flex justify-between font-bold text-lg"><span>{t('pos.total', locale)}</span><span>{formatCurrency(grandTotal, currency)}</span></div>
            </div>
            <Separator />
            <div>
              <Label className="text-xs font-medium">{t('pos.payment', locale)}</Label>
              <div className="flex gap-1 mt-1 flex-wrap">
                {([['cash', t('pos.cash', locale)], ['card', t('pos.card', locale)], ['transfer', t('pos.transfer', locale)], ['gift_card', t('pos.giftCard', locale)]] as const).map(([val, label]) => (
                  <Button key={val} variant={paymentMethod === val ? 'default' : 'outline'} size="sm" className="flex-1 text-xs min-w-0" onClick={() => { setPaymentMethod(val as any); if (val !== 'gift_card') { setGcCard(null); setIsSplitPayment(false); } }}>{label}</Button>
                ))}
              </div>
            </div>
            {paymentMethod === 'gift_card' && !isSplitPayment && (
              <motion.div initial={{ opacity: 0, height: 0 }} animate={{ opacity: 1, height: 'auto' }} className="space-y-2 border rounded-lg p-3 bg-muted/30">
                <div className="flex gap-2">
                  <div className="flex-1"><Label className="text-xs">{t('pos.giftCardNumber', locale)}</Label><Input value={gcNumber} onChange={e => setGcNumber(e.target.value)} placeholder="GC-XXXX-XXXX-XXXX" className="mt-1 h-8 text-sm" /></div>
                  <div className="w-24"><Label className="text-xs">{t('pos.giftCardPin', locale)}</Label><Input value={gcPin} onChange={e => setGcPin(e.target.value)} placeholder="000000" maxLength={6} className="mt-1 h-8 text-sm" /></div>
                </div>
                <Button variant="outline" size="sm" onClick={handleLookUpGiftCard} disabled={gcLoading || !gcNumber.trim()} className="w-full">{gcLoading ? <Loader2 className="w-3 h-3 mr-1 animate-spin" /> : <Gift className="w-3 h-3 mr-1" />}{t('pos.lookUpCard', locale)}</Button>
                {gcCard && (
                  <div className="flex items-center justify-between text-sm p-2 bg-green-50 dark:bg-green-900/20 rounded-md">
                    <span className="text-green-700 dark:text-green-400 font-medium">{t('pos.cardBalance', locale)}:</span>
                    <span className="font-bold text-green-700 dark:text-green-400">{formatCurrency(gcCard.currentBalance, currency)}</span>
                  </div>
                )}
              </motion.div>
            )}
            {paymentMethod === 'gift_card' && isSplitPayment && gcCard && (
              <motion.div initial={{ opacity: 0, height: 0 }} animate={{ opacity: 1, height: 'auto' }} className="space-y-2 border rounded-lg p-3 bg-amber-50 dark:bg-amber-900/20">
                <p className="text-xs font-semibold text-amber-700 dark:text-amber-400">{t('pos.splitPayment', locale)}</p>
                <div className="flex justify-between text-sm"><span>{t('pos.giftCardAmount', locale)}:</span><span className="font-medium">{formatCurrency(giftCardAmount, currency)}</span></div>
                <div className="flex justify-between text-sm"><span>{t('pos.remainingAmount', locale)}:</span><span className="font-bold text-amber-700 dark:text-amber-400">{formatCurrency(remainingAmount, currency)}</span></div>
                <Separator />
                <p className="text-xs text-muted-foreground">{t('pos.selectPaymentMethod', locale)}</p>
                <div className="flex gap-1">
                  {([['cash', t('pos.cash', locale)], ['card', t('pos.card', locale)], ['transfer', t('pos.transfer', locale)]] as const).map(([val, label]) => (
                    <Button key={val} variant={splitSecondaryMethod === val ? 'default' : 'outline'} size="sm" className="flex-1 text-xs" onClick={() => setSplitSecondaryMethod(val as any)}>{label}</Button>
                  ))}
                </div>
                {splitSecondaryMethod === 'cash' && (
                  <div><Label className="text-xs">{t('pos.amountReceived', locale)}</Label><Input type="number" min={0} step={0.01} value={cashReceived || ''} onChange={e => setCashReceived(parseFloat(e.target.value) || 0)} placeholder={String(remainingAmount)} className="mt-1 h-8 text-sm" />
                  {cashReceived >= remainingAmount && remainingAmount > 0 && (
                    <div className="flex justify-between font-medium text-xs text-green-600 mt-1"><span>{t('pos.change', locale)}</span><span>{formatCurrency(Math.max(0, cashReceived - remainingAmount), currency)}</span></div>
                  )}
                  </div>
                )}
              </motion.div>
            )}
            {paymentMethod === 'cash' && (
              <motion.div initial={{ opacity: 0, height: 0 }} animate={{ opacity: 1, height: 'auto' }} className="space-y-2">
                <div><Label className="text-xs">{t('pos.amountReceived', locale)}</Label><Input type="number" min={0} step={0.01} value={cashReceived || ''} onChange={e => setCashReceived(parseFloat(e.target.value) || 0)} placeholder="0.00" className="mt-1" /></div>
                {cashReceived >= grandTotal && grandTotal > 0 && (
                  <div className="flex justify-between font-medium text-sm text-green-600"><span>{t('pos.change', locale)}</span><span>{formatCurrency(change, currency)}</span></div>
                )}
              </motion.div>
            )}
            <div className="flex gap-2">
              <Button variant="outline" onClick={handleHoldSale} disabled={cart.length === 0} className="flex-1"><Clock className="w-4 h-4 mr-1" />{t('pos.hold', locale)}</Button>
              <Button onClick={handleCheckout} disabled={cart.length === 0 || checkingOut} className="flex-1 bg-gradient-to-r from-blue-700 to-blue-500">{checkingOut ? <Loader2 className="w-4 h-4 animate-spin" /> : <><CreditCard className="w-4 h-4 mr-1" />{t('pos.charge', locale)}</>}</Button>
            </div>
          </CardContent>
        </Card>
      </div>

      {/* Held Sales Dialog */}
      <Dialog open={showHeldSales} onOpenChange={setShowHeldSales}>
        <DialogContent className="max-w-md">
          <DialogHeader><DialogTitle>{t('pos.heldSales', locale)}</DialogTitle></DialogHeader>
          <div className="space-y-2 max-h-64 overflow-y-auto">
            {heldSales.map(h => (
              <div key={h.id} className="flex items-center justify-between p-3 border rounded-lg">
                <div><p className="text-sm font-medium">{h.customerName || t('pos.walkIn', locale)} — {h.cart.length} {t('pos.items', locale)}</p><p className="text-xs text-muted-foreground">{new Date(h.heldAt).toLocaleString()}</p></div>
                <div className="flex gap-1">
                  <Button size="sm" variant="outline" onClick={() => handleResumeSale(h)}><RefreshCw className="w-3 h-3 mr-1" />{t('pos.resume', locale)}</Button>
                  <Button size="sm" variant="ghost" className="text-destructive" onClick={() => handleDeleteHeld(h.id)}><Trash2 className="w-3 h-3" /></Button>
                </div>
              </div>
            ))}
          </div>
        </DialogContent>
      </Dialog>

      {/* Barcode Scanner Dialog */}
      <Dialog open={showScanner} onOpenChange={setShowScanner}>
        <DialogContent className="max-w-lg">
          <DialogHeader><DialogTitle>{t('pos.search', locale)}</DialogTitle></DialogHeader>
          <BarcodeScanner onAddToOrder={handleBarcodeScanned} />
        </DialogContent>
      </Dialog>

      {/* Receipt Dialog */}
      <Dialog open={!!receiptOrder} onOpenChange={() => setReceiptOrder(null)}>
        <DialogContent className="max-w-sm">
          <DialogHeader><DialogTitle className="text-center">{t('pos.receiptTitle', locale)}</DialogTitle></DialogHeader>
          <div className="border rounded-lg p-4 space-y-3 text-sm font-mono" id="receipt-print">
            <div className="text-center space-y-1">
              <p className="font-bold text-base">{currentTenant?.name || 'Business'}</p>
              <p className="text-xs text-muted-foreground">{receiptOrder?.date ? new Date(receiptOrder.date).toLocaleString() : ''}</p>
              <p className="text-xs text-muted-foreground">{receiptOrder?.id || ''}</p>
            </div>
            <Separator />
            {(receiptOrder?.items || []).map((item: any, idx: number) => (
              <div key={idx} className="flex justify-between">
                <div><p className="text-xs">{item.name}</p><p className="text-xs text-muted-foreground">{item.qty} × {formatCurrency(item.price, currency)}</p></div>
                <span>{formatCurrency(item.price * item.qty, currency)}</span>
              </div>
            ))}
            <Separator />
            <div className="space-y-1">
              <div className="flex justify-between"><span>{t('pos.subtotal', locale)}</span><span>{formatCurrency(receiptOrder?.subtotal || 0, currency)}</span></div>
              {receiptOrder?.discountPct > 0 && <div className="flex justify-between text-amber-600"><span>{t('pos.discountLabel', locale)} ({receiptOrder.discountPct}%)</span><span>-{formatCurrency(receiptOrder?.discountAmount || 0, currency)}</span></div>}
              <div className="flex justify-between"><span>{t('pos.tax', locale)}</span><span>{formatCurrency(receiptOrder?.taxAmount || 0, currency)}</span></div>
              <Separator />
              <div className="flex justify-between font-bold text-base"><span>{t('pos.total', locale)}</span><span>{formatCurrency(receiptOrder?.totalAmount || 0, currency)}</span></div>
            </div>
            <Separator />
            <div className="text-xs space-y-1">
              <div className="flex justify-between"><span>{t('pos.payment', locale)}:</span><span>{paymentMethodLabel(receiptOrder?.paymentMethod)}</span></div>
              <div className="flex justify-between"><span>{t('pos.customer', locale)}:</span><span>{receiptOrder?.customerName || t('pos.walkIn', locale)}</span></div>
              {receiptOrder?.paymentMethod === 'cash' && receiptOrder.cashReceived > 0 && (
                <>
                  <div className="flex justify-between"><span>{t('pos.amountReceived', locale)}:</span><span>{formatCurrency(receiptOrder.cashReceived, currency)}</span></div>
                  <div className="flex justify-between"><span>{t('pos.change', locale)}:</span><span>{formatCurrency(receiptOrder.changeAmount, currency)}</span></div>
                </>
              )}
              {receiptOrder?.paymentMethod === 'split' && receiptOrder?.splitDetails && (
                <>
                  {receiptOrder.splitDetails.cash > 0 && <div className="flex justify-between"><span>{t('pos.cash', locale)}:</span><span>{formatCurrency(receiptOrder.splitDetails.cash, currency)}</span></div>}
                  {receiptOrder.splitDetails.card > 0 && <div className="flex justify-between"><span>{t('pos.card', locale)}:</span><span>{formatCurrency(receiptOrder.splitDetails.card, currency)}</span></div>}
                  {receiptOrder.splitDetails.giftCard > 0 && <div className="flex justify-between"><span>{t('pos.giftCard', locale)}:</span><span>{formatCurrency(receiptOrder.splitDetails.giftCard, currency)}</span></div>}
                  {receiptOrder.splitDetails.transfer > 0 && <div className="flex justify-between"><span>{t('pos.transfer', locale)}:</span><span>{formatCurrency(receiptOrder.splitDetails.transfer, currency)}</span></div>}
                </>
              )}
              {receiptOrder?.paymentMethod === 'gift_card' && (
                <div className="flex justify-between"><span>{t('pos.giftCard', locale)}:</span><span>{formatCurrency(receiptOrder?.totalAmount || 0, currency)}</span></div>
              )}
            </div>
            <p className="text-center text-xs text-muted-foreground mt-2">{t('pos.receipt', locale)}</p>
          </div>
          <DialogFooter className="flex gap-2">
            <Button variant="outline" className="flex-1" onClick={() => setReceiptOrder(null)}>OK</Button>
            <Button className="flex-1 bg-gradient-to-r from-blue-700 to-blue-500" onClick={handlePrint}><Copy className="w-4 h-4 mr-2" />{t('pos.receipt', locale)}</Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

function TenantSuppliersPage() {
  const { currentTenant, locale } = useAppStore() as any;
  const [suppliers, setSuppliers] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [showForm, setShowForm] = useState(false);
  const [editing, setEditing] = useState<any>(null);
  const [search, setSearch] = useState('');
  const [catFilter, setCatFilter] = useState('all');
  const [form, setForm] = useState({ name: '', contact: '', email: '', phone: '', address: '', category: '', rating: 0, notes: '' });
  const [poCounts, setPoCounts] = useState<Record<string, number>>({});
  const tid = currentTenant?.id;

  const catKeys = ['suppliers.catFood', 'suppliers.catPackaging', 'suppliers.catEquipment', 'suppliers.catRaw', 'suppliers.catServices', 'suppliers.catElectronics', 'suppliers.catClothing', 'suppliers.catHealth', 'suppliers.catOther'];
  const categoryOptions = catKeys.map(k => ({ value: k.replace('suppliers.cat', '').toLowerCase(), label: t(k, locale) }));

  const load = useCallback(() => {
    if (!tid) return;
    authFetch(`/api/tenant/${tid}/suppliers`).then(r => r.json()).then(d => { setSuppliers(Array.isArray(d) ? d : []); setLoading(false); }).catch(() => setLoading(false));
    authFetch(`/api/tenant/${tid}/purchase-orders`).then(r => r.json()).then(d => {
      const counts: Record<string, number> = {};
      (Array.isArray(d) ? d : []).forEach((po: any) => { if (po.supplierId) { counts[po.supplierId] = (counts[po.supplierId] || 0) + 1; } });
      setPoCounts(counts);
    }).catch(() => {});
  }, [tid]);
  useEffect(() => { load(); }, [load]);

  const defaultForm = { name: '', contact: '', email: '', phone: '', address: '', category: '', rating: 0, notes: '' };
  const openCreate = () => { setEditing(null); setForm({ ...defaultForm }); setShowForm(true); };
  const openEdit = (row: any) => { setEditing(row); setForm({ name: row.name || '', contact: row.contact || '', email: row.email || '', phone: row.phone || '', address: row.address || '', category: row.category || '', rating: row.rating || 0, notes: row.notes || '' }); setShowForm(true); };

  const handleSave = async () => {
    if (!form.name) return;
    const isEdit = !!editing?.id;
    try {
      await authFetchJSON(`/api/tenant/${tid}/suppliers`, { method: isEdit ? 'PUT' : 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(isEdit ? { id: editing.id, ...form } : form) });
      setShowForm(false); setEditing(null); load();
      toast.success(t('suppliers.saved', locale));
    } catch (e: any) { toast.error(e.message); }
  };

  const handleDelete = async (row: any) => {
    if (!confirm(t('common.confirmDelete', locale))) return;
    try {
      await authFetchJSON(`/api/tenant/${tid}/suppliers`, { method: 'DELETE', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ id: row.id }) });
      load(); toast.success(t('suppliers.deleted', locale));
    } catch (e: any) { toast.error(e.message); }
  };

  const allCats = Array.from(new Set(suppliers.map(s => s.category).filter(Boolean)));
  const filtered = suppliers.filter((s: any) => {
    const matchSearch = !search || s.name?.toLowerCase().includes(search.toLowerCase()) || s.contact?.toLowerCase().includes(search.toLowerCase());
    const matchCat = catFilter === 'all' || s.category === catFilter;
    return matchSearch && matchCat;
  });

  const renderStars = (rating: number) => (
    <div className="flex gap-0.5">
      {[1, 2, 3, 4, 5].map(i => <Star key={i} className={`w-3.5 h-3.5 ${i <= rating ? 'text-amber-400 fill-amber-400' : 'text-muted-foreground'}`} />)}
    </div>
  );

  const catLabel = (cat: string) => {
    const found = categoryOptions.find(o => o.value === cat?.toLowerCase());
    return found ? found.label : cat || '—';
  };

  if (loading) return <PageSkeleton type="table" />;

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between flex-wrap gap-4">
        <div className="flex items-center gap-3">
          <div className="p-2.5 rounded-xl bg-gradient-to-br from-cyan-500 to-blue-500 shadow-lg"><Truck className="w-5 h-5 text-white" /></div>
          <div><h1 className="text-2xl font-bold">{t('suppliers.title', locale)}</h1><p className="text-sm text-muted-foreground">{t('suppliers.subtitle', locale)}</p></div>
        </div>
        <Button onClick={openCreate} className="bg-gradient-to-r from-blue-700 to-blue-500"><Plus className="w-4 h-4 mr-2" />{t('suppliers.name', locale)}</Button>
      </div>

      {filtered.length === 0 ? (
        <EmptyState icon={Truck} title={t('suppliers.empty', locale)} description={t('suppliers.emptyDesc', locale)} action={t('suppliers.name', locale)} onAction={openCreate} />
      ) : (
        <>
          <div className="flex flex-wrap gap-3 items-center">
            <div className="relative max-w-xs flex-1"><Search className="w-4 h-4 absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" /><Input placeholder={t('suppliers.name', locale)} value={search} onChange={e => setSearch(e.target.value)} className="pl-10" /></div>
            <Select value={catFilter} onValueChange={setCatFilter}>
              <SelectTrigger className="w-[180px]"><SelectValue placeholder={t('suppliers.category', locale)} /></SelectTrigger>
              <SelectContent>
                <SelectItem value="all">{t('pos.all', locale)}</SelectItem>
                {allCats.map(c => <SelectItem key={c} value={c}>{catLabel(c)}</SelectItem>)}
              </SelectContent>
            </Select>
          </div>
          <Card>
            <div className="overflow-x-auto">
              <table className="w-full text-sm">
                <thead><tr className="border-b bg-muted/50">
                  <th className="text-left px-4 py-3 font-medium">{t('suppliers.name', locale)}</th>
                  <th className="text-left px-4 py-3 font-medium">{t('suppliers.contact', locale)}</th>
                  <th className="text-left px-4 py-3 font-medium">{t('suppliers.email', locale)}</th>
                  <th className="text-left px-4 py-3 font-medium">{t('suppliers.phone', locale)}</th>
                  <th className="text-left px-4 py-3 font-medium">{t('suppliers.category', locale)}</th>
                  <th className="text-left px-4 py-3 font-medium">{t('suppliers.rating', locale)}</th>
                  <th className="text-center px-4 py-3 font-medium">PO</th>
                  <th className="text-center px-4 py-3 font-medium">{t('po.actions', locale)}</th>
                </tr></thead>
                <tbody>
                  {filtered.map((s: any) => (
                    <tr key={s.id} className="border-b hover:bg-muted/30 transition-colors">
                      <td className="px-4 py-3 font-medium">{s.name}</td>
                      <td className="px-4 py-3 text-muted-foreground">{s.contact || '—'}</td>
                      <td className="px-4 py-3 text-muted-foreground">{s.email || '—'}</td>
                      <td className="px-4 py-3 text-muted-foreground">{s.phone || '—'}</td>
                      <td className="px-4 py-3">{s.category ? <Badge variant="secondary">{catLabel(s.category)}</Badge> : '—'}</td>
                      <td className="px-4 py-3">{renderStars(s.rating || 0)}</td>
                      <td className="px-4 py-3 text-center">{poCounts[s.id] || '—'}</td>
                      <td className="px-4 py-3 text-center">
                        <div className="flex items-center justify-center gap-1">
                          <Button variant="ghost" size="sm" onClick={() => openEdit(s)}><Edit className="w-3.5 h-3.5" /></Button>
                          <Button variant="ghost" size="sm" className="text-destructive hover:text-destructive" onClick={() => handleDelete(s)}><Trash2 className="w-3.5 h-3.5" /></Button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </Card>
        </>
      )}

      {/* Create/Edit Dialog */}
      <Dialog open={showForm} onOpenChange={setShowForm}>
        <DialogContent className="max-w-lg max-h-[85vh] overflow-y-auto">
          <DialogHeader><DialogTitle>{editing ? t('suppliers.name', locale) : t('suppliers.name', locale)}</DialogTitle></DialogHeader>
          <div className="space-y-4 mt-4">
            <div><Label>{t('suppliers.name', locale)} *</Label><Input value={form.name} onChange={e => setForm(f => ({ ...f, name: e.target.value }))} className="mt-1" /></div>
            <div><Label>{t('suppliers.contact', locale)}</Label><Input value={form.contact} onChange={e => setForm(f => ({ ...f, contact: e.target.value }))} className="mt-1" /></div>
            <div className="grid grid-cols-2 gap-4">
              <div><Label>{t('suppliers.email', locale)}</Label><Input type="email" value={form.email} onChange={e => setForm(f => ({ ...f, email: e.target.value }))} className="mt-1" /></div>
              <div><Label>{t('suppliers.phone', locale)}</Label><Input value={form.phone} onChange={e => setForm(f => ({ ...f, phone: e.target.value }))} className="mt-1" /></div>
            </div>
            <div><Label>{t('suppliers.address', locale)}</Label><Input value={form.address} onChange={e => setForm(f => ({ ...f, address: e.target.value }))} className="mt-1" /></div>
            <div><Label>{t('suppliers.category', locale)}</Label>
              <Select value={form.category} onValueChange={v => setForm(f => ({ ...f, category: v }))}>
                <SelectTrigger className="mt-1"><SelectValue placeholder={t('suppliers.category', locale)} /></SelectTrigger>
                <SelectContent>{categoryOptions.map(c => <SelectItem key={c.value} value={c.value}>{c.label}</SelectItem>)}</SelectContent>
              </Select>
            </div>
            <div>
              <Label>{t('suppliers.rating', locale)}</Label>
              <div className="flex gap-1 mt-2">
                {[1, 2, 3, 4, 5].map(i => (
                  <button key={i} type="button" onClick={() => setForm(f => ({ ...f, rating: f.rating === i ? 0 : i }))}>
                    <Star className={`w-6 h-6 cursor-pointer transition-colors ${i <= form.rating ? 'text-amber-400 fill-amber-400' : 'text-muted-foreground hover:text-amber-300'}`} />
                  </button>
                ))}
              </div>
            </div>
            <div><Label>{t('suppliers.notes', locale)}</Label><Textarea value={form.notes} onChange={e => setForm(f => ({ ...f, notes: e.target.value }))} rows={3} className="mt-1" /></div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setShowForm(false)}>{t('common.cancel', locale)}</Button>
            <Button onClick={handleSave} disabled={!form.name} className="bg-gradient-to-r from-blue-700 to-blue-500">{t('suppliers.saved', locale)}</Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

// --- Salon Pages ---
function TenantAppointmentsPage() {
  const locale = useAppStore(s => s.locale);
  const { currentTenant, currency } = useAppStore() as any;
  const [items, setItems] = useState<any[]>([]);
  const [stylists, setStylists] = useState<any[]>([]);
  const [services, setServices] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [showForm, setShowForm] = useState(false);
  const [editing, setEditing] = useState<any>(null);
  const [dateFilter, setDateFilter] = useState<'all' | 'today' | 'week'>('all');
  const [statusFilter, setStatusFilter] = useState('all');
  const [form, setForm] = useState({ clientName: '', stylistId: '', serviceId: '', date: '', duration: 60, status: 'scheduled', notes: '' });
  const tid = currentTenant?.id;

  const load = useCallback(() => {
    if (!tid) return;
    Promise.all([
      authFetch(`/api/tenant/${tid}/appointments`).then(r => r.json()),
      authFetch(`/api/tenant/${tid}/stylists`).then(r => r.json()),
      authFetch(`/api/tenant/${tid}/salon-services`).then(r => r.json()),
    ]).then(([appts, sty, svc]) => { setItems(Array.isArray(appts) ? appts : []); setStylists(Array.isArray(sty) ? sty : []); setServices(Array.isArray(svc) ? svc : []); setLoading(false); }).catch(() => setLoading(false));
  }, [tid]);
  useEffect(() => { load(); }, [load]);

  const openCreate = () => { setEditing(null); setForm({ clientName: '', stylistId: '', serviceId: '', date: '', duration: 60, status: 'scheduled', notes: '' }); setShowForm(true); };
  const openEdit = (row: any) => { setEditing(row); setForm({ clientName: row.clientName || '', stylistId: row.stylistId || '', serviceId: row.serviceId || '', date: row.date ? new Date(row.date).toISOString().slice(0, 16) : '', duration: row.duration || 60, status: row.status || 'scheduled', notes: row.notes || '' }); setShowForm(true); };
  const handleSave = async () => {
    const isEdit = !!editing?.id;
    await authFetch(`/api/tenant/${tid}/appointments`, { method: isEdit ? 'PUT' : 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(isEdit ? { id: editing.id, ...form } : form) });
    setShowForm(false); load(); toast.success(isEdit ? '¡Cita actualizada!' : '¡Cita reservada!');
  };
  const handleDelete = async (row: any) => {
    await authFetch(`/api/tenant/${tid}/appointments`, { method: 'DELETE', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ id: row.id }) });
    load(); toast.success('¡Cita eliminada!');
  };

  const statusColors: Record<string, string> = { confirmed: 'bg-green-500/10 text-green-600 border-green-500/30', scheduled: 'bg-blue-500/10 text-blue-600 border-blue-500/30', pending: 'bg-amber-500/10 text-amber-600 border-amber-500/30', completed: 'bg-gray-500/10 text-gray-600 border-gray-500/30', cancelled: 'bg-red-500/10 text-red-600 border-red-500/30' };

  const now = new Date();
  const todayStr = now.toISOString().slice(0, 10);
  const weekEnd = new Date(now); weekEnd.setDate(weekEnd.getDate() + (7 - weekEnd.getDay()));

  const filteredItems = items.filter((item: any) => {
    if (statusFilter !== 'all' && item.status !== statusFilter) return false;
    if (!item.date) return false;
    const d = new Date(item.date);
    if (dateFilter === 'today') return d.toISOString().slice(0, 10) === todayStr;
    if (dateFilter === 'week') return d >= new Date(todayStr) && d <= weekEnd;
    return true;
  });

  const todayItems = items.filter((item: any) => item.date && new Date(item.date).toISOString().slice(0, 10) === todayStr);
  const weekItems = items.filter((item: any) => item.date && new Date(item.date) >= new Date(todayStr) && new Date(item.date) <= weekEnd);
  const completedToday = todayItems.filter((i: any) => i.status === 'completed').length;

  const grouped = filteredItems.reduce((acc: any, item: any) => {
    const d = item.date ? new Date(item.date).toLocaleDateString('es') : 'Sin programar';
    if (!acc[d]) acc[d] = [];
    acc[d].push(item);
    return acc;
  }, {});

  // Timeline slots for today view: 8 AM to 8 PM, 30-min slots
  const timeSlots: string[] = [];
  for (let h = 8; h < 20; h++) {
    timeSlots.push(`${h.toString().padStart(2, '0')}:00`);
    timeSlots.push(`${h.toString().padStart(2, '0')}:30`);
  }

  const getSlotIndex = (dateStr: string) => {
    const d = new Date(dateStr);
    const totalMin = (d.getHours() - 8) * 60 + d.getMinutes();
    return Math.max(0, Math.min(Math.floor(totalMin / 30), timeSlots.length - 1));
  };

  const slotHeight = 3; // rem per 30-min slot

  const statusLabels: Record<string, string> = { scheduled: 'Programada', confirmed: 'Confirmada', pending: 'Pendiente', completed: 'Completada', cancelled: 'Cancelada' };

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between flex-wrap gap-3">
        <div><h1 className="text-2xl font-bold">Citas</h1><p className="text-sm text-muted-foreground">Gestionar horario del salón</p></div>
        <Button onClick={openCreate} className="bg-gradient-to-r from-blue-700 to-blue-500"><Plus className="w-4 h-4 mr-2" />Nueva Cita</Button>
      </div>

      {/* Stats Row */}
      <div className="grid grid-cols-3 gap-4">
        <Card className="p-4"><p className="text-xs text-muted-foreground">Citas Hoy</p><p className="text-2xl font-bold">{todayItems.length}</p></Card>
        <Card className="p-4"><p className="text-xs text-muted-foreground">Esta Semana</p><p className="text-2xl font-bold">{weekItems.length}</p></Card>
        <Card className="p-4"><p className="text-xs text-muted-foreground">Completadas Hoy</p><p className="text-2xl font-bold text-green-600">{completedToday}</p></Card>
      </div>

      {/* Filter Bar */}
      <div className="flex flex-wrap gap-2 items-center">
        <div className="flex gap-1">
          {([['all', 'Todas'], ['today', 'Hoy'], ['week', 'Esta Semana']] as const).map(([val, label]) => (
            <Button key={val} variant={dateFilter === val ? 'default' : 'outline'} size="sm" onClick={() => setDateFilter(val)} className="text-xs">{label}</Button>
          ))}
        </div>
        <Select value={statusFilter} onValueChange={setStatusFilter}>
          <SelectTrigger className="w-36 h-8 text-xs"><SelectValue placeholder={t("pm.filter.status", locale)} /></SelectTrigger>
          <SelectContent>
            <SelectItem value="all">Todos los estados</SelectItem>
            <SelectItem value="scheduled">Programada</SelectItem>
            <SelectItem value="confirmed">Confirmada</SelectItem>
            <SelectItem value="pending">Pendiente</SelectItem>
            <SelectItem value="completed">Completada</SelectItem>
            <SelectItem value="cancelled">Cancelada</SelectItem>
          </SelectContent>
        </Select>
      </div>

      {loading ? <PageSkeleton type="table" /> : filteredItems.length === 0 ? (
        <EmptyState icon={Calendar} title="Sin citas" description="Reserva tu primera cita" action="Nueva Cita" onAction={openCreate} />
      ) : (
        <>
          {/* Today Timeline View */}
          {dateFilter === 'today' && (
            <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} className="border rounded-xl overflow-hidden">
              <div className="bg-muted/50 px-4 py-2"><h3 className="text-sm font-semibold">Horario de Hoy</h3></div>
              <div className="overflow-y-auto max-h-[50vh]">
                <div className="relative min-h-[720px]">
                  {timeSlots.map((slot, idx) => (
                    <div key={slot} className="flex border-b border-dashed border-muted/30" style={{ minHeight: `${slotHeight}rem` }}>
                      <div className="w-16 text-xs text-muted-foreground py-1 text-right pr-3 shrink-0">{slot}</div>
                      <div className="flex-1 border-l border-muted/30 relative" />
                    </div>
                  ))}
                  {todayItems.map((apt: any) => {
                    const stylist = stylists.find((s: any) => s.id === apt.stylistId);
                    const service = services.find((s: any) => s.id === apt.serviceId);
                    const slotIdx = getSlotIndex(apt.date);
                    const spanSlots = Math.max(1, Math.ceil((apt.duration || 30) / 30));
                    return (
                      <div
                        key={apt.id}
                        className="absolute left-16 right-2 z-10 cursor-pointer"
                        style={{ top: `${slotIdx * slotHeight * 16}px`, height: `${spanSlots * slotHeight * 16 - 4}px` }}
                        onClick={() => openEdit(apt)}
                      >
                        <div className={`h-full rounded-lg px-2 py-1 text-xs ${statusColors[apt.status] || 'bg-blue-500/10'} border overflow-hidden`}>
                          <p className="font-semibold truncate">{apt.clientName || 'Sin cliente'}</p>
                          <p className="text-[10px] truncate">{service?.name || ''} • {stylist?.name || ''}</p>
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            </motion.div>
          )}

          {/* Grouped List View */}
          <div className="space-y-6 max-h-[70vh] overflow-y-auto">
            {Object.entries(grouped).sort().map(([date, appointments]: [string, any]) => (
              <div key={date}>
                <h3 className="text-sm font-semibold text-muted-foreground mb-3">{date}</h3>
                <div className="grid sm:grid-cols-2 lg:grid-cols-3 gap-3">
                  {(appointments as any[]).map((apt: any) => {
                    const stylist = stylists.find((s: any) => s.id === apt.stylistId);
                    const service = services.find((s: any) => s.id === apt.serviceId);
                    return (
                      <motion.div key={apt.id} layout className={`p-4 rounded-xl border ${statusColors[apt.status] || ''} hover:shadow-md transition-all`}>
                        <div className="flex items-start justify-between">
                          <div className="flex-1 min-w-0">
                            <p className="font-semibold text-sm">{apt.clientName || 'Sin cliente'}</p>
                            <p className="text-xs text-muted-foreground mt-1">{service?.name || 'Sin servicio'} • {apt.duration}min</p>
                            <p className="text-xs text-muted-foreground">Estilista: {stylist?.name || 'Sin asignar'}</p>
                            <p className="text-xs text-muted-foreground">{apt.date ? new Date(apt.date).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) : ''}</p>
                          </div>
                          <div className="flex gap-1"><Button variant="ghost" size="icon" className="w-7 h-7" onClick={() => openEdit(apt)}><Edit className="w-3 h-3" /></Button><Button variant="ghost" size="icon" className="w-7 h-7 text-destructive" onClick={() => handleDelete(apt)}><Trash2 className="w-3 h-3" /></Button></div>
                        </div>
                        <div className="mt-2"><Badge className="text-[10px]" variant="outline">{statusLabels[apt.status] || apt.status}</Badge></div>
                      </motion.div>
                    );
                  })}
                </div>
              </div>
            ))}
          </div>
        </>
      )}
      <Dialog open={showForm} onOpenChange={setShowForm}>
        <DialogContent className="max-w-lg max-h-[85vh] overflow-y-auto">
          <DialogHeader><DialogTitle>{editing ? 'Editar Cita' : 'Nueva Cita'}</DialogTitle></DialogHeader>
          <div className="space-y-4 mt-4">
            <div><Label>Nombre del Cliente *</Label><Input value={form.clientName} onChange={e => setForm(p => ({ ...p, clientName: e.target.value }))} /></div>
            <div className="grid grid-cols-2 gap-4">
              <div><Label>Estilista</Label><Select value={form.stylistId} onValueChange={v => setForm(p => ({ ...p, stylistId: v }))}>
                <SelectTrigger><SelectValue placeholder="Seleccionar estilista" /></SelectTrigger>
                <SelectContent>{stylists.map((s: any) => <SelectItem key={s.id} value={s.id}>{s.name}</SelectItem>)}</SelectContent>
              </Select></div>
              <div><Label>Servicio</Label><Select value={form.serviceId} onValueChange={v => setForm(p => ({ ...p, serviceId: v }))}>
                <SelectTrigger><SelectValue placeholder="Seleccionar servicio" /></SelectTrigger>
                <SelectContent>{services.map((s: any) => <SelectItem key={s.id} value={s.id}>{s.name}</SelectItem>)}</SelectContent>
              </Select></div>
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div><Label>Fecha y Hora *</Label><Input type="datetime-local" value={form.date} onChange={e => setForm(p => ({ ...p, date: e.target.value }))} /></div>
              <div><Label>Duración (min)</Label><Input type="number" value={form.duration} onChange={e => setForm(p => ({ ...p, duration: parseInt(e.target.value) || 60 }))} /></div>
            </div>
            <div><Label>{t("pm.filter.status", locale)}</Label><Select value={form.status} onValueChange={v => setForm(p => ({ ...p, status: v }))}>
              <SelectTrigger><SelectValue /></SelectTrigger>
              <SelectContent><SelectItem value="scheduled">Programada</SelectItem><SelectItem value="confirmed">Confirmada</SelectItem><SelectItem value="pending">Pendiente</SelectItem><SelectItem value="completed">Completada</SelectItem><SelectItem value="cancelled">Cancelada</SelectItem></SelectContent>
            </Select></div>
            <div><Label>Notas</Label><Textarea value={form.notes} onChange={e => setForm(p => ({ ...p, notes: e.target.value }))} /></div>
            <Button onClick={handleSave} disabled={!form.clientName || !form.date} className="w-full bg-gradient-to-r from-blue-700 to-blue-500">{editing ? 'Guardar Cambios' : 'Reservar Cita'}</Button>
          </div>
        </DialogContent>
      </Dialog>
    </div>
  );
}

