    try { await authFetch(`/api/tenant/${currentTenant.id}/design-gallery`, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(form) }); setShowCreate(false); setForm({ title: '', description: '', category: 'Tortas', tags: '' }); load(); toast.success('Design agregado!'); } catch { toast.error('Error'); }
